39	export function compare(val1, val2, tol = 0.1) {
40	  if (val1 !== null && val2 !== null && typeof val1 === "object" && typeof val2 === "object") {
41	    // Both are non-null objects
42	
43	    if (Array.isArray(val1) && Array.isArray(val2)) {
44	      expect(val1).toHaveLength(val2.length);
45	
46	      for (let i = 0; i < val1.length; ++i) {
47	        compare(val1[i], val2[i], tol);
48	      }
49	    } else {
50	      expect(Object.keys(val1)).toHaveLength(Object.keys(val2).length);
51	
52	      for (let key in val1) {
53	        compare(val1[key], val2[key], tol);
54	      }
55	    }
56	  } else {
57	    // At least one of them is not an object
58	    // First check that both have the same type
59	    expect(typeof val1).toEqual(typeof val2);
60	
61	    if (typeof val1 === "number" && (!Number.isInteger(val1) || !Number.isInteger(val2))) {
62	      // If both are numbers and at least one of them is not an integer
63	      expect(val1).toBeCloseTo(val2, -Math.log10(tol));
64	    } else {
65	      // Perform equality test
66	      expect(val1).toEqual(val2);
67	    }
68	  }
69	}
