82	export async function collect_tests(filename) {
83	  const model_types = fs.readdirSync(models_dir);
84	  const all_tests = [];
85	  for (const model_type of model_types) {
86	    const dir = path.join(models_dir, model_type);
87	
88	    if (!fs.existsSync(dir) || !fs.statSync(dir).isDirectory()) {
89	      continue;
90	    }
91	
92	    const file = path.join(dir, `test_${filename}_${model_type}.js`);
93	    if (!fs.existsSync(file)) {
94	      continue;
95	    }
96	
97	    const items = await import(file);
98	    all_tests.push([model_type, items]);
99	  }
100	  return all_tests;
101	}
